code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Avatar, Badge, Button, icon } from 'decantr/components';

code.example:
function ActivityFeed({ search, view }) {
  const { div, span, p, h4, time } = tags;

  const activities = [
    { user: 'Alice Johnson', initials: 'AJ', action: 'created a new project', type: 'create', time: '2 hours ago', date: 'Today' },
    { user: 'Bob Smith', initials: 'BS', action: 'commented on issue #42', type: 'comment', time: '4 hours ago', date: 'Today' },
    { user: 'Carol White', initials: 'CW', action: 'deployed v2.1.0 to production', type: 'deploy', time: '1 day ago', date: 'Yesterday' },
  ];

  const grouped = {};
  activities.forEach(a => { (grouped[a.date] = grouped[a.date] || []).push(a); });

  return div({ class: css('_flex _col _gap2 _w[100%]') },
    ...Object.entries(grouped).flatMap(([date, items]) => [
      h4({ class: css('_textsm _fgmuted _fontmedium _py2') }, date),
      ...items.map(item =>
        div({ class: css('_flex _row _gap3 _items[start] _py2') },
          Avatar({ size: 'sm', fallback: item.initials }),
          div({ class: css('_flex _col _gap1 _flex1') },
            p({ class: css('_textsm') },
              span({ class: css('_fontmedium') }, item.user),
              ` ${item.action}`
            ),
            time({ class: css('_textxs _fgmuted') }, item.time)
          ),
          Badge({ variant: 'outline', size: 'sm' }, item.type)
        )
      )
    ]),
    Button({ variant: 'outline', size: 'sm', class: css('_self[center] _mt4') }, icon('chevron-down', { size: '0.75rem' }), ' Load more')
  );
}

