function ActivityFeedDetailed({ search, view }) {
  const { div, span, p, time } = tags;

  const activities = [
    { user: 'Alice Johnson', initials: 'AJ', action: 'Created a new project', detail: 'Project Alpha has been initialized with the default template and CI/CD pipeline.', type: 'create', time: '2 hours ago', attachments: 1 },
    { user: 'Bob Smith', initials: 'BS', action: 'Commented on issue #42', detail: 'We should consider refactoring the auth middleware before the next release.', type: 'comment', time: '4 hours ago', attachments: 0 },
  ];

  return div({ class: css('_flex _col _gap4 _w[100%]') },
    ...activities.map(item =>
      div({ class: css('_flex _col _gap2 _p4 _r3 _border _border[var(--border)]') },
        div({ class: css('_flex _row _gap3 _aic') },
          Avatar({ size: 'sm', fallback: item.initials }),
          div({ class: css('_flex _col _flex1') },
            span({ class: css('_textsm _fontmedium') }, item.user),
            time({ class: css('_textxs _fgmuted') }, item.time)
          ),
          Badge({ variant: 'outline', size: 'sm' }, item.type)
        ),
        p({ class: css('_textsm _fontmedium') }, item.action),
        p({ class: css('_textsm _fgmuted') }, item.detail),
        item.attachments > 0 ? div({ class: css('_flex _gap2 _aic _textsm _fgmuted') },
          icon('paperclip', { size: '0.75rem' }), `${item.attachments} attachment(s)`
        ) : null,
        div({ class: css('_flex _gap2 _pt2 _bordertop _border[var(--border)]') },
          Button({ variant: 'ghost', size: 'xs' }, icon('reply', { size: '0.75rem' }), ' Reply'),
          Button({ variant: 'ghost', size: 'xs' }, icon('thumbs-up', { size: '0.75rem' }), ' Like'),
          Button({ variant: 'ghost', size: 'xs' }, icon('share', { size: '0.75rem' }), ' Share')
        )
      )
    ),
    Button({ variant: 'outline', size: 'sm', class: css('_self[center]') }, icon('chevron-down', { size: '0.75rem' }), ' Load more')
  );
}

